const md = $input.item.json.content;

// Basic markdown-to-HTML parser
function markdownToHtml(markdown) {
  if (!markdown) return '';

  let html = markdown
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    // Headers
    .replace(/^# (.*)$/gm, '<h1>$1</h1>')
    .replace(/^## (.*)$/gm, '<h2>$1</h2>')
    .replace(/^### (.*)$/gm, '<h3>$1</h3>')
    .replace(/^#### (.*)$/gm, '<h4>$1</h4>')
    // Code blocks
    .replace(/```([\s\S]*?)```/g, '<pre><code>$1</code></pre>')
    // Inline bold & italics
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.*?)\*/g, '<em>$1</em>')
    .replace(/`([^`]+)`/g, '<code>$1</code>')
    // Hyperlinks
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank">$1</a>')
    // Blockquotes
    .replace(/^> (.*)$/gm, '<blockquote>$1</blockquote>')
    // Table conversions
    .replace(/\| (.+?) \|/g, '<td>$1</td>')
    .replace(/<\/td>\n<td>/g, '</td><td>')
    // Paragraph replacements & lists
    .replace(/^- (.*)$/gm, '<li>$1</li>');

  // Group lists
  html = html.replace(/((?:<li>.*<\/li>\n?)+)/g, '<ul>$1</ul>');

  // Convert tables lines to rows
  // Note: For simplicity of email rendering, table rows are split by newlines
  let lines = html.split('\n');
  let inTable = false;
  for (let i = 0; i < lines.length; i++) {
    if (lines[i].includes('<td>')) {
      if (!inTable) {
        lines[i] = '<table><tr>' + lines[i] + '</tr>';
        inTable = true;
      } else {
        if (lines[i].includes('---')) {
          lines[i] = ''; // Skip header divider
        } else {
          lines[i] = '<tr>' + lines[i] + '</tr>';
        }
      }
    } else {
      if (inTable) {
        lines[i] = '</table>' + lines[i];
        inTable = false;
      }
    }
  }
  html = lines.join('\n');

  // Replace standard double newlines with spacing
  html = html.replace(/\n\n/g, '<br><br>');

  return html;
}

const parsedHtml = markdownToHtml(md);

